# Solution
def Solution.binary_search(self, arr: list[int], target: int) -> int:
  if not arr or target < arr[0]:
    return -1
  low, high = 0, len(arr) - 1
  while low <= high:
    mid = low + (high - low) // 2
    if arr[mid] == target:
      return mid
    elif arr[mid] > target:
      high = mid - 1
    else:
      low = mid + 1
  return -1

